    def is_prime(n):
        if n < 2:
            return False
        for i in range(2, int(n**0.5) + 1):
            if n % i == 0:
                return False
        return True

    def multiply_primes():
        primes = []
        num = a
        while num > 1:
            for prime in primes:
                if num % prime == 0:
                    return [prime] * (num // prime)
            for i in range(2, int(num**0.5) + 1):
