class EvenOddPalindrome {
    public static List<Integer> evenOddPalindrome(int n) {
        int evenCount = 0;
        int oddCount = 0;

        for (int i = 1; i <= n; i++) {
            String str = Integer.toString(i);
            if (isPalindrome(str)) {
                if (isEven(Integer.parseInt(str))) {
                    evenCount++;
                } else {
                    oddCount++;
                }
            }
        }

        List<Integer> result = new ArrayList<>();
