import java.io.*;
import java.lang.*;
import java.util.*;

public class Maximum {

    public static List<Object> maximum(List<Integer> arr, int k) {
        // Initialize a priority queue to store the k largest numbers.
        PriorityQueue<Integer> pq = new PriorityQueue<>((a, b) -> b - a);

        // Iterate over the array. For each number, push it into the priority queue if the size of the queue is less than k or if the number is greater than the smallest number in the queue.
        for (int num : arr) {
            pq.add(num);
            if (pq.size() > k) {
                pq.poll();
            }
        }

        // Convert the priority queue into a list and return it.
        List<Object> result = new ArrayList<>();
        while (!pq.isEmpty()) {
            result.add(pq.poll());
        }

        Collections.reverse(result);  // Reverse the list to get the correct order.

        return result;
    }

    public static void main(String[] args) {
        List<Integer> arr = Arrays.asList(-3, -4, 5);
        int k = 3;
        System.out.println(maximum(arr, k));
    }
}
