class Tri {
    /**
     * Everyone knows Fibonacci sequence, it was studied deeply by mathematicians in 
     * the last couple centuries. However, what people don't know is Tribonacci sequence.
     * Tribonacci sequence is defined by the recurrence:
     * tri(1) = 3
     * tri(n) = 1 + n / 2, if n is even.
     * tri(n) =  tri(n - 1) + tri(n - 2) + tri(n + 1), if n is odd.
     * For example:
     * tri(2) = 1 + (2 / 2) = 2
     * tri(4) = 3
     * tri(3) = tri(2) + tri(1) + tri(4)
     *        = 2 + 3 + 3 = 8 
     * You are given a non-negative integer number n, you have to a return a list of the 
     * first n + 1 numbers of the Tribonacci sequence.
     * Examples:
     * tri(3) = [1, 3, 2, 8]
     *
     */
    public static List<Number> tri(int n) {
        List<Number> tribonacciSequence = new ArrayList<>();

        // base cases
        if (n == 0) {
            return tribonacciSequence;
        }
        tribonacciSequence.add(new Integer(1));

        if (n > 0) {
            tribonacciSequence.add(new Integer(3));

            if (n > 1) {
                tribonacciSequence.add(new Integer(2));

                for (int i = 4; i <= n + 1; i++) {
                    int triNum;

                    // even case
                    if (i % 2 == 0) {
                        triNum = 1 + i / 2;
                    }
                    // odd case
                    else {
                        int prevTriNum1 = tribonacciSequence.get(i - 1).intValue();
                        int prevTriNum2 = tribonacciSequence.get(i - 2).intValue();
                        if (i < n + 1) {
                            int nextTriNum = tribonacciSequence.get(i - 3).intValue();
                            triNum = prevTriNum1 + prevTriNum2 + nextTriNum;
                        } else {
                            triNum = prevTriNum1 + prevTriNum2;
                        }
                    }

                    tribonacciSequence.add(new Integer(triNum));
                }
            }
        }

        return tribonacciSequence;
    }
}
```

