    public static List<String> bf(String planet1, String planet2) {

        // Define a list of planets in order from the sun
        List<String> planets = new ArrayList<>(Arrays.asList("Mercury", "Venus", "Earth", "Mars", "Jupiter", "Saturn", "Uranus", "Neptune"));

        // Check if the input planet names are correct
        if (!planets.contains(planet1) || !planets.contains(planet2)) {
            return new ArrayList<>();
        }

        // Find the indices of the two planets in the list
        int index1 = planets.indexOf(planet1);
        int index2 = planets.indexOf(planet2);

        // If planet1 is after planet2, swap them
        if (index1 > index2) {
            int temp = index1;
            index1 = index2;
            index2 = temp;
        }

        // Get the planets between planet1 and planet2
        List<String> result = new ArrayList<>();
        for (int i = index1 + 1; i < index2; i++) {
            result.add(planets.get(i));
        }

        return result;
    }
}
