    public static int maxFill(int[][] grid, int capacity) {
        if (grid == null || grid.length == 0) return 0;

        int totalWater = 0; // total water in wells
        int bucketsNeeded = 0; // number of times to lower the bucket

        for (int[] row : grid) { // iterate over each well
            for (int unit : row) {
                if (unit == 1) { // add water from this well to total
                    totalWater += 1;
                }
            }
