        while (totalWater > 0) { // until all water is gone
            int bucketSpace = capacity; // space left in current bucket

            for (int[] row : grid) {
                for (int unit : row) {
                    if (unit == 1 && bucketSpace > 0) { // fill up this well
                        totalWater -= 1;
                        bucketSpace--;
                    }
                }
            }

            bucketsUsed++; // increment number of buckets used

            while (bucketSpace < capacity) { // if not all space in bucket is used, empty it
                int waterInBucket = 0;

