function rightAngleTriangle(a, b, c) {
    let isRight = false;

    // If one side is 0 and another side is also 0 then it's not possible to have a right angled triangle.
    if ((a === 0 && (b === 0 || c === 0)) || 
        (b === 0 && (a === 0 || c === 0)) || 
        (c === 0 && (a === 0 || b === 0))) {
        return false;
    }

    // If the sum of lengths of two sides is equal to the length of the third side, then it's not a right angled triangle.
    if ((a + b) === c || 
        (a + c) === b || 
        (b + c) === a) {
        return false;
    }

    // If none of above conditions are met, then the sides can form a right-angled triangle.
    for (let i = 1; i <= Math.max(a, b, c); i++) {
        let sideA = i * i;
        let sideB = (Math.max(a, b) - i) * (Math.max(a, b) - i);
        let hypotenuse = (Math.max(c, a, b) - i) * (Math.max(c, a, b) - i);

        if (sideA + sideB === hypotenuse) {
            isRight = true;
            break;
        }
    }

    return isRight;
}
