        /// You are given two positive integers n and m, and your task is to compute the
        /// average of the integers from n through m (including n and m). 
        /// Round the answer to the nearest integer and convert that to binary.
        /// If n is greater than m, return -1.
        /// Example:
        /// RoundedAvg(1, 5) => "0b11"
        /// RoundedAvg(7, 5) => -1
        /// RoundedAvg(10, 20) => "0b1111"
        /// RoundedAvg(20, 33) => "0b11010"
        /// 
        /// </summary>
        public static object RoundedAvg(int n, int m)
        {
            if (n > m) return -1;

            double sum = 0;
            for (int i = n; i <= m; i++)
            {
                sum += i;
            }

            double average = Math.Round(sum / ((double)(m - n + 1)));

            string binaryAverage = Convert.ToString(average, 2);

            return "0b" + binaryAverage.PadLeft(Math.Max(n, m).ToString("b").Length, '0');
        }
    }
}
