func solve(s string) string {
	r := regexp.MustCompile(`[a-zA-Z]+`)
	if matched := r.FindString(s); matched != "" {
		return r.ReplaceAllStringFunc(s, func(s string) string {
			for i := 0; i < len(s); i++ {
				if s[i] >= 'a' && s[i] <= 'z' {
					s = s[:i] + string(s[i] - ('a' - 'A')) + s[i+1:]
				} else if s[i] >= 'A' && s[i] <= 'Z' {
