    $sequence = [];
    if ($n == 0) {
        return [$sequence];
    }

    // Base cases: tri(1) = 3, tri(2) = 2
    if ($n <= 2) {
        for ($i = 0; $i < $n + 1; $i++) {
            if ($i == 0) {
                $sequence[] = 3;
            } elseif ($i == 1) {
                $sequence[] = 2;
            } else {
                $sequence[] = 8;
            }
        }
    }

    // General case: tri(n) = 1 + n/2 (even) or tri(n - 1) + tri(n - 2) + tri(n + 1) (odd)
    for ($i = 3; $i <= $n; $i++) {
        if ($i % 2 == 0) { // even
            $sequence[] = 1 + $i / 2;
        } else { // odd
            $lastThreeValues = array_slice($sequence, -3);
            $sequence[] = $lastThreeValues[0] + $lastThreeValues[1] + $lastThreeValues[2];
        }
    }

    return $sequence;
}
